index.html: <!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Flip Card</title>
    <link rel="stylesheet" href="styles.css">
</head>
<body>
    <div class="max-w-md mx-auto mt-12 bg-white p-8 rounded shadow" id="card-container">
        <button class="bg-blue-500 hover:bg-blue-700 text-white font-bold py-2 px-4 rounded mb-4" onclick="flipCard()">Flip</button>
        <div class="card">
            <div class="front">
                <h2 class="text-2xl font-bold">Card Title</h2>
                <p class="text-lg">This is a paragraph of text.</p>
            </div>
            <div class="back" style="display: none;">
                <h2 class="text-2xl font-bold">Card Back</h2>
                <p class="text-lg">This is the back of the card.</p>
            </div>
        </div>
    </div>
    <script src="script.js"></script>
</body>
</html>
styles.css: .card {
    width: 300px;
    height: 200px;
    perspective: 1000px;
}

.card .front, .card .back {
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    backface-visibility: hidden;
    transition: transform 0.5s;
}

.card .back {
    transform: rotateY(180deg);
}

#card-container {
    cursor: pointer;
}
script.js: function flipCard() {
    const card = document.querySelector('.card');
    card.classList.toggle('flipped');
}

document.addEventListener('click', function(e) {
    if (e.target.classList.contains('bg-blue-500')) return;
    const card = document.querySelector('.card');
    card.classList.remove('flipped');
});
